const fs = require('fs');
const path = require('path');
const crypto = require('crypto');

// ==== Config estática (pode ser movida para Variáveis Globais) ====
const cfg = {
  "site": {
    "name": "Aventuras de Comida de Rua pelo Mundo",
    "base_url": "https://SEU-DOMINIO.com",
    "language": "pt-BR",
    "author": "Street Food Bot",
    "timezone": "America/Sao_Paulo"
  },
  "categories": [
    "Street Food por Continente",
    "Street Food Vegano",
    "Street Food Barata",
    "Guias Gastronômicos",
    "Gadgets e Dicas"
  ],
  "longtails": [
    {"keyword": "street food vegano em Bangkok","category": "Street Food Vegano","country": "Tailândia","city": "Bangkok"},
    {"keyword": "comidas de rua baratas em Lisboa","category": "Street Food Barata","country": "Portugal","city": "Lisboa"},
    {"keyword": "street food noturna em Tóquio","category": "Guias Gastronômicos","country": "Japão","city": "Tóquio"},
    {"keyword": "onde comer barato em Roma","category": "Street Food Barata","country": "Itália","city": "Roma"},
    {"keyword": "comida de rua no México (tacos e mercados)","category": "Street Food por Continente","country": "México","city": "Cidade do México"}
  ],
  "rotation_policy": {"posts_per_week": 2,"min_days_between_same_keyword": 180}
};

const CONTENT_DIR = process.env.CONTENT_DIR || '/data/content';
const SEED = process.env.SEED || '';

function slugify(text){
  return text
    .toLowerCase()
    .normalize('NFD')
    .replace(/[^\p{L}\p{N}\s-]/gu, '')
    .trim()
    .replace(/[\s_-]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

function today(){
  return new Date().toISOString().split('T')[0];
}

function stableHash(s){
  return crypto.createHash('sha256').update(s).digest('hex').slice(0, 12);
}

function readManifest(manifestPath){
  try{
    const raw = fs.readFileSync(manifestPath, 'utf8');
    const j = JSON.parse(raw);
    return Array.isArray(j.posts) ? j : {posts: []};
  }catch(err){
    return {posts: []};
  }
}

function writeJson(p, obj){
  fs.mkdirSync(path.dirname(p), {recursive: true});
  fs.writeFileSync(p, JSON.stringify(obj, null, 2), 'utf8');
}

function pickKeyword(cfg, manifest){
  const used = {};
  for(const p of manifest.posts){
    used[p.keyword] = p.date;
  }

  const minDays = Number(cfg.rotation_policy?.min_days_between_same_keyword ?? 180);
  const candidates = cfg.longtails.filter(entry => {
    const last = used[entry.keyword];
    if(!last) return true;
    const lastDate = new Date(last + 'T00:00:00Z');
    const delta = (Date.now() - lastDate.getTime()) / 86400000;
    return delta >= minDays;
  });

  const pool = candidates.length ? candidates : cfg.longtails;
  const rng = crypto.createHash('sha256').update(Date.now().toString() + SEED).digest('hex');
  const idx = parseInt(rng.slice(0, 8), 16) % pool.length;
  return pool[idx];
}

function fallbackContent(entry){
  const {keyword, city, country, category} = entry;
  const title = `${keyword.charAt(0).toUpperCase() + keyword.slice(1)}: guia rápido para comer bem`.slice(0, 60);
  const description = `Roteiro de street food em ${city} (${country}): preços médios, onde ir, dicas de segurança e FAQ.`.slice(0, 155);

  const foods = [
    {name: 'Prato clássico local', price: 'R$ 15–35', where: 'Mercado central / feiras', tip: 'Chega cedo para pegar comida fresca.'},
    {name: 'Lanche de rua famoso', price: 'R$ 10–25', where: 'Ruas movimentadas perto de metrô', tip: 'Fila local costuma ser bom sinal.'},
    {name: 'Bebida típica', price: 'R$ 6–18', where: 'Bancas com alta rotatividade', tip: 'Prefira sem gelo se duvidar da água.'},
    {name: 'Doce popular', price: 'R$ 8–22', where: 'Barracas com vitrine fechada', tip: 'Evite doce exposto horas no sol.'},
    {name: 'Opção veg/vegana', price: 'R$ 12–30', where: 'Praças de alimentação de mercados', tip: 'Confirme se o caldo/molho é sem origem animal.'},
    {name: 'Snack de noite', price: 'R$ 12–28', where: 'Feiras noturnas', tip: 'Peça porções pequenas e repita o que gostar.'},
    {name: 'Especial picante', price: 'R$ 14–32', where: 'Bancas populares entre locais', tip: 'Pergunte pelo nível de pimenta antes.'},
    {name: 'Sobremesa gelada', price: 'R$ 10–24', where: 'Carrinhos próximos a praças', tip: 'Prefira gelo feito na hora ou industrializado.'}
  ];

  const safety = [
    'Escolha barracas com preparo na hora e alta rotatividade.',
    'Use água lacrada e desconfie de gelo de procedência duvidosa.',
    'Carteira e celular na frente do corpo em áreas lotadas.',
    'Cheque preços antes de pedir e prefira cardápio visível.',
    'Se algo parecer morno ou parado, escolha outra barraca.',
    'Em caso de desconforto estomacal, hidrate e procure farmácia local.'
  ];

  const faq = [
    {q: `Melhor horário para comer street food em ${city}?`, a: 'Almoço é mais tranquilo; noite é mais vibrante. Chegue cedo para pegar tudo fresco.'},
    {q: 'Dá para pagar com cartão?', a: 'Algumas barracas aceitam, mas leve dinheiro trocado para não depender.'},
    {q: 'Como evitar golpe turístico?', a: 'Compare preços em 2–3 bancas e evite abordagem muito insistente.'},
    {q: 'É seguro comer carne na rua?', a: 'Prefira carnes bem passadas e que saem direto da chapa ou fritadeira.'},
    {q: 'Onde encontrar opções veganas?', a: 'Mercados centrais e feiras costumam ter bancas com legumes salteados e tofu.'}
  ];

  const tags = [slugify(category), slugify(country), slugify(city), 'street-food', 'viagem-barata'];

  const intro = `${city} tem comida de rua direta, barata e com personalidade. Aqui vai um roteiro rápido do que comer, onde ir e como evitar cilada.`;
  const cta = 'Curtiu? Salva o guia e compartilha com quem vai viajar contigo.';

  return {title, description, h1: keyword, intro, foods, safety_tips: safety, stay_section: `Fica em regiões centrais de ${city} para ir a pé aos mercados e feiras.`, faq, cta, tags};
}

function estimateReadingTime(post){
  const blocks = [post.title, post.description, post.intro, post.cta, ...post.safety_tips, ...post.faq.map(x=>x.q + ' ' + x.a), ...post.foods.map(x=>x.name)];
  const words = blocks.join(' ').split(/\s+/).filter(Boolean).length;
  return Math.max(3, Math.ceil(words/220));
}

function generate(){
  fs.mkdirSync(path.join(CONTENT_DIR, 'posts'), {recursive: true});
  const manifestPath = path.join(CONTENT_DIR, 'posts', 'posts.json');
  const manifest = readManifest(manifestPath);
  const entry = pickKeyword(cfg, manifest);
  const slug = slugify(`${entry.keyword}-${entry.city}-${entry.country}-${stableHash(entry.keyword+entry.city+entry.country)}`);
  const base = fallbackContent(entry);
  const post = {
    slug,
    keyword: entry.keyword,
    category: entry.category,
    country: entry.country,
    city: entry.city,
    title: base.title,
    description: base.description,
    date: today(),
    reading_time_minutes: estimateReadingTime(base),
    h1: base.h1 || entry.keyword,
    intro: base.intro,
    foods: base.foods,
    safety_tips: base.safety_tips,
    stay_section: base.stay_section,
    faq: base.faq,
    cta: base.cta,
    tags: base.tags
  };

  const postPath = path.join(CONTENT_DIR, 'posts', `${slug}.json`);
  writeJson(postPath, post);

  const existing = manifest.posts.filter(p => p.slug !== slug);
  existing.push({
    slug: post.slug,
    title: post.title,
    description: post.description,
    keyword: post.keyword,
    category: post.category,
    country: post.country,
    city: post.city,
    date: post.date,
    reading_time_minutes: post.reading_time_minutes
  });

  existing.sort((a,b)=> a.date < b.date ? 1 : -1);
  writeJson(manifestPath, {posts: existing});

  return {post, files: {postPath, manifestPath}};
}

const output = generate();
return [{json: output}];
